CREATE TABLE departments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL
);

CREATE TABLE employees (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    department_id INTEGER,
    name TEXT NOT NULL,
    role TEXT NOT NULL,
    salary REAL,
    hire_date DATE
);

